4082 bool InstCombinerImpl::removeInstructionsBeforeUnreachable(Instruction &I) {
4083   // Try to remove the previous instruction if it must lead to unreachable.
4084   // This includes instructions like stores and "llvm.assume" that may not get
4085   // removed by simple dead code elimination.
