4187 void InstCombinerImpl::handlePotentiallyDeadBlocks(
4188     SmallVectorImpl<BasicBlock *> &Worklist) {
4189   while (!Worklist.empty()) {
4190     BasicBlock *BB = Worklist.pop_back_val();
4191     if (!all_of(predecessors(BB), [&](BasicBlock *Pred) {
4192           return DeadEdges.contains({Pred, BB}) || DT.dominates(BB, Pred);
4193         }))
4194       continue;
4195 
4196     handleUnreachableFrom(&BB->front(), Worklist);
